mapper.insert:

select SEQ_EML_NO.NEXTVAL FROM DUAL

INSERT INTO EMAIL(EML_NO,  EML_SNDR_ID
    , EML_TTL
    , EML_CN
    , EML_SNDNG_DT
    , EML_EMRG_YN
    , FILE_ID
    , EML_OTSD_SNDR_ADDR
    , EML_OTSD_RCVR_ADDR
    , EML_OTSD_YN
) values (#{emlNo}
    , #{emlSndrId}
    , #{emlTtl}
    , #{emlCn}
    , SYSDATE
    , #{emlEmrgYn}
    , #{fileId}
    , #{emlOtsdSndrAddr}
    , #{emlOtsdRcvrAddr}
    , #{emlOtsdYn})

mapper.select:
SELECT COUNT(*) FROM (SELECT ROW_NUMBER() OVER (ORDER BY AL.EML_NO DESC) RNUM , AL.* FROM (SELECT A.EML_NO , A.EML_FILE_GROUP_NO , B.EML_RCVR_ID , A.EML_SNDR_ID , A.EML_TTL , A.EML_CN , A.EML_SNDNG_DT , A.EML_EMRG_YN , B.EML_IMPT_YN -- , B.EML_RCPTN_YN -- , B.EML_RCVNG_DT -- , B.EML_DEL_YN -- , B.EML_RCVR_TYPE -- , A.EML_SNDR_DEL_YN , A.EML_OTSD_RCVR_ADDR , A.EML_OTSD_SNDR_ADDR , A.EML_STTS , A.FILE_ID , C.EMP_NM , C.EMP_JBGD , D.DEPT_NM FROM EMAIL A LEFT OUTER JOIN EMAIL_RECEIVER B ON A.EML_NO=B.EML_NO LEFT OUTER JOIN EMPLOYEE C ON A.EML_SNDR_ID=C.EMP_ID LEFT OUTER JOIN DEPARTMENT D ON C.DEPT_CD = D.DEPT_CD WHERE B.EMP_ID=#{empId} AND B.EML_DEL_YN='N' AND A.EML_SNDR_DEL_YN='N'
) AL where 1=1
) T

SELECT T.* FROM (SELECT ROW_NUMBER() OVER (ORDER BY AL.EML_NO DESC) RNUM , AL.* FROM (SELECT A.EML_NO , A.EML_FILE_GROUP_NO , B.EML_RCVR_ID , A.EML_SNDR_ID , A.EML_TTL , A.EML_CN , A.EML_SNDNG_DT , A.EML_EMRG_YN , B.EML_IMPT_YN -- , B.EML_RCPTN_YN -- , B.EML_RCVNG_DT -- , B.EML_DEL_YN -- , B.EML_RCVR_TYPE -- , A.EML_SNDR_DEL_YN , A.EML_OTSD_RCVR_ADDR , A.EML_OTSD_SNDR_ADDR , A.EML_STTS , A.FILE_ID , C.EMP_NM , C.EMP_JBGD , D.DEPT_NM FROM EMAIL A LEFT OUTER JOIN EMAIL_RECEIVER B ON A.EML_NO=B.EML_NO LEFT OUTER JOIN EMPLOYEE C ON A.EML_SNDR_ID=C.EMP_ID LEFT OUTER JOIN DEPARTMENT D ON C.DEPT_CD = D.DEPT_CD WHERE B.EMP_ID=#{empId} AND B.EML_DEL_YN='N' AND A.EML_SNDR_DEL_YN='N'
) AL where 1=1
) T WHERE RNUM BETWEEN (#{currentPage} * #{pageNum}) - ( #{pageNum} - 1) AND (#{currentPage} * #{pageNum})

SELECT COUNT(*) FROM (SELECT ROW_NUMBER() OVER (ORDER BY AL.EML_NO DESC) RNUM , AL.* FROM (SELECT A.EML_NO , A.EML_FILE_GROUP_NO , B.EML_RCVR_ID , A.EML_SNDR_ID , A.EML_TTL , A.EML_CN , A.EML_SNDNG_DT , A.EML_EMRG_YN , B.EML_IMPT_YN -- , B.EML_RCPTN_YN -- , B.EML_RCVNG_DT -- , B.EML_DEL_YN -- , B.EML_RCVR_TYPE -- , A.EML_SNDR_DEL_YN , A.EML_OTSD_RCVR_ADDR , A.EML_OTSD_SNDR_ADDR , A.EML_STTS , A.FILE_ID , C.EMP_NM , C.EMP_JBGD , D.DEPT_NM FROM EMAIL A LEFT OUTER JOIN EMAIL_RECEIVER B ON A.EML_NO=B.EML_NO LEFT OUTER JOIN EMPLOYEE C ON A.EML_SNDR_ID=C.EMP_ID LEFT OUTER JOIN DEPARTMENT D ON C.DEPT_CD = D.DEPT_CD WHERE B.EMP_ID=#{empId} AND B.EML_DEL_YN='Y' AND (B.EML_DEL_PMNT_YN='N') --휴지통에만 있는 (영구삭제 N의 경우) AND A.EML_SNDR_DEL_YN='N'
) AL where 1=1
) T

SELECT T.* FROM (SELECT ROW_NUMBER() OVER (ORDER BY AL.EML_NO DESC) RNUM , AL.* FROM (SELECT A.EML_NO , A.EML_FILE_GROUP_NO , B.EML_RCVR_ID , A.EML_SNDR_ID , A.EML_TTL , A.EML_CN , A.EML_SNDNG_DT , A.EML_EMRG_YN , B.EML_IMPT_YN -- , B.EML_RCPTN_YN -- , B.EML_RCVNG_DT -- , B.EML_DEL_YN -- , B.EML_RCVR_TYPE -- , A.EML_SNDR_DEL_YN , A.EML_OTSD_RCVR_ADDR , A.EML_OTSD_SNDR_ADDR , A.EML_STTS , A.FILE_ID , C.EMP_NM , C.EMP_JBGD , D.DEPT_NM FROM EMAIL A LEFT OUTER JOIN EMAIL_RECEIVER B ON A.EML_NO=B.EML_NO LEFT OUTER JOIN EMPLOYEE C ON A.EML_SNDR_ID=C.EMP_ID LEFT OUTER JOIN DEPARTMENT D ON C.DEPT_CD = D.DEPT_CD WHERE B.EMP_ID=#{empId} AND B.EML_DEL_YN='Y' AND (B.EML_DEL_PMNT_YN='N') --휴지통에만 있는 (영구삭제 N의 경우) AND A.EML_SNDR_DEL_YN='N'
) AL where 1=1
) T WHERE RNUM BETWEEN (#{currentPage} * #{pageNum}) - ( #{pageNum} - 1) AND (#{currentPage} * #{pageNum})

